func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const INF_COST = 1e18
	type cand struct {
		assignIdx int
		costDelta float64
	}

	// Precompute which assigns are non-empty (have stations/routes already)
	hasContent := make([]bool, MAXASSIGNS)
	nonEmptyCnt := 0
	for i := 0; i < MAXASSIGNS; i++ {
		if i < dispatch.AssignsLen && dispatch.Assigns[i].StationsLen > 0 {
			hasContent[i] = true
			nonEmptyCnt++
		}
	}

	// Process orders sequentially
	for jj := range oris {
		bestCand := cand{-1, INF_COST}

		// Try all existing non-empty assigns first
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if !hasContent[ii] {
				continue
			}
			prevCost := dispatch.Assigns[ii].Cost

			added := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
			if added {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 {
					delta := newCost - prevCost
					if delta < bestCand.costDelta {
						bestCand.assignIdx = ii
						bestCand.costDelta = delta
					}
				}
				// Rollback trial insertion
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		// Also try a potential new assign (empty) if we haven't filled MAXASSIGNS
		// We evaluate it separately because empty assign has no previous route cost,
		// so we compute base cost from current station to ori to des back to depot? Not needed here;
		// Just check feasibility via AddShip followed by GenRoute.
		if dispatch.AssignsLen < MAXASSIGNS {
			ii := dispatch.AssignsLen // candidate new assign index
			// Temporarily use that slot; we'll roll back if we don't pick it.
			added := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
			if added {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 {
					// For new assign, treat delta as newCost (since prevCost was zero/undefined).
					// We compare against a threshold relative to existing options.
					// Here we just store as-is and decide later.
					delta := newCost
					// Compare fairly: if better than best among existing, take it.
					if delta < bestCand.costDelta {
						bestCand.assignIdx = ii
						bestCand.costDelta = delta
					}
				}
				// Rollback
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		// Apply the best feasible insertion found
		inserted := false
		if bestCand.assignIdx >= 0 {
			ok := dispatch.Assigns[bestCand.assignIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[bestCand.assignIdx].GenRoute()
				if dispatch.Assigns[bestCand.assignIdx].Cost >= 0 {
					inserted = true
					if bestCand.assignIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = bestCand.assignIdx + 1
					}
				} else {
					// Should not happen since trial succeeded, but rollback to be safe
					dispatch.Assigns[bestCand.assignIdx].RemoveShip(total_ship + jj)
					dispatch.Assigns[bestCand.assignIdx].GenRoute()
				}
			}
		}

		// Fallback: if still not inserted, force into a new assign regardless of cost
		if !inserted {
			// Find first free assign slot (could be within AssignsLen if some are truly empty after rollback?)
			slot := -1
			for ii := 0; ii < MAXASSIGNS; ii++ {
				if ii >= dispatch.AssignsLen || dispatch.Assigns[ii].StationsLen == 0 {
					slot = ii
					break
				}
			}
			if slot >= 0 {
				ok := dispatch.Assigns[slot].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[slot].GenRoute()
					if dispatch.Assigns[slot].Cost >= 0 {
						inserted = true
						if slot >= dispatch.AssignsLen {
							dispatch.AssignsLen = slot + 1
						}
					}
				}
			}
		}

		// Update content flags after successful insertion
		if inserted && bestCand.assignIdx >= 0 {
			hasContent[bestCand.assignIdx] = true
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

